public class debug_test {
    public static void main(String[] args) {
        String testString = "0302-0601-3F06W220ZBLALALACANDC04060302MOE.model";

        System.out.println("Original string: " + testString);
        System.out.println("Original string length: " + testString.length());

        byte[] buff = new byte[100];
        int len = TarUtils.formatNameBytes(testString, buff, 0, buff.length);

        System.out.print("Formatted into bytes: ");
        for (int i = 0; i < len && buff[i] != 0; i++) {
            System.out.print(Integer.toHexString(buff[i] & 0xFF) + " ");
        }
        System.out.println();

        String parsed = TarUtils.parseName(buff, 0, len);
        System.out.println("Parsed string: " + parsed);
        System.out.println("Are they equal? " + testString.equals(parsed));

        System.out.println("Original string (as hex chars):");
        for (int i = 0; i < testString.length(); i++) {
            System.out.print(Integer.toHexString((int)testString.charAt(i)) + " ");
        }
        System.out.println();
    }
}

